const body = $input.first().json.body || $input.first().json || {};

// Validaciones mínimas
if (!body.empleado_id || !body.motivo || !body.hora_declarada_cst || !body.hora_real_checkin_utc) {
  return [{ json: {
    _error: true,
    codigo: 'INVALID_PAYLOAD',
    mensaje: 'Faltan campos obligatorios (empleado_id, motivo, hora_declarada_cst, hora_real_checkin_utc)'
  }}];
}

if (String(body.motivo).trim().length < 10) {
  return [{ json: {
    _error: true,
    codigo: 'MOTIVO_CORTO',
    mensaje: 'El motivo debe tener al menos 10 caracteres'
  }}];
}

// Generar ID interno único
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const idInterno = 'INC-OLV-' + body.empleado_id + '-' + ts;

// Construir incidencia con propuesta inicial del empleado
const nueva = {
  id_interno: idInterno,
  odoo_incidencia_id: null,
  tipo: 'olvido_entrada',
  empleado_id: body.empleado_id,
  empleado_nombre: body.empleado_nombre || '',
  fecha_creacion: new Date().toISOString(),
  attendance_id: body.attendance_id_creado || null,
  hora_real_checkin_utc: body.hora_real_checkin_utc,
  geolocation: body.geolocation || null,
  foto_base64: body.foto_base64 || null,
  propuestas: [{
    paso: 1,
    rol: 'empleado',
    user_id: body.empleado_id,
    usuario: body.empleado_nombre || 'empleado',
    timestamp: new Date().toISOString(),
    hora_propuesta_cst: body.hora_declarada_cst,
    comentario: body.motivo,
    accion: 'solicitud'
  }],
  status: 'pendiente_supervisor',
  hora_final_aplicada_utc: null,
  aplicado_en_odoo: false
};

return [{ json: { nueva_incidencia: nueva } }];

const ghResp = $input.first().json;
const prev   = $('Code - Validar payload').item.json;
const nueva  = prev.nueva_incidencia;

let archivo = { version: 1, incidencias: [] };
let sha = null;

if (ghResp && ghResp.content && ghResp.sha) {
  sha = ghResp.sha;
  try {
    const decoded = Buffer.from(String(ghResp.content).replace(/\n/g, ''), 'base64').toString('utf8');
    archivo = JSON.parse(decoded);
    if (!archivo.version) archivo.version = 1;
    if (!Array.isArray(archivo.incidencias)) archivo.incidencias = [];
  } catch (e) {
    archivo = { version: 1, incidencias: [] };
  }
}

// Más reciente al inicio
archivo.incidencias.unshift(nueva);

const nuevoStr = JSON.stringify(archivo, null, 2);
const nuevoB64 = Buffer.from(nuevoStr, 'utf8').toString('base64');

return [{
  json: {
    sha: sha || '',
    content: nuevoB64,
    message: 'incidencia: olvido_entrada ' + (nueva.empleado_nombre || 'emp?') + ' (' + nueva.id_interno + ')',
    nueva_incidencia: nueva
  }
}];

const prev = $('Code - Merge incidencia').item.json;
const n = prev.nueva_incidencia;
return [{
  json: {
    success: true,
    id_interno: n.id_interno,
    status: n.status,
    mensaje: 'Incidencia creada. Tu supervisor la revisará pronto.'
  }
}];
